import assert from 'assert'
import { geo, geoFromHeaders, isInRegion, geoDistance } from './geo'

// Test geo() with Vercel headers
{
  const headers = new Headers({
    'x-vercel-ip-city': 'New York',
    'x-vercel-ip-country': 'US',
    'x-vercel-ip-country-region': 'NY',
    'x-vercel-ip-latitude': '40.7128',
    'x-vercel-ip-longitude': '-74.0060',
    'x-vercel-ip-timezone': 'America/New_York',
  })
  const result = geo({ headers })
  assert.strictEqual(result.city, 'New York')
  assert.strictEqual(result.countryCode, 'US')
  assert.strictEqual(result.country, 'United States')
  assert.strictEqual(result.region, 'NY')
  assert.strictEqual(result.latitude, '40.7128')
  assert.strictEqual(result.longitude, '-74.0060')
  assert.strictEqual(result.timezone, 'America/New_York')
  console.log('✓ geo() with Vercel headers')
}

// Test geoFromHeaders() with Cloudflare fallback
{
  const headers = new Headers({
    'cf-ipcountry': 'DE',
  })
  const result = geoFromHeaders(headers)
  assert.strictEqual(result.countryCode, 'DE')
  assert.strictEqual(result.country, 'Germany')
  assert.strictEqual(result.city, undefined)
  console.log('✓ geoFromHeaders() with Cloudflare fallback')
}

// Test that Vercel country takes precedence over Cloudflare
{
  const headers = new Headers({
    'x-vercel-ip-country': 'FR',
    'cf-ipcountry': 'DE',
  })
  const result = geoFromHeaders(headers)
  assert.strictEqual(result.countryCode, 'FR')
  assert.strictEqual(result.country, 'France')
  console.log('✓ Vercel country takes precedence over Cloudflare')
}

// Test isInRegion() with matching and non-matching regions
{
  const g = { countryCode: 'US', country: 'United States' }
  assert.strictEqual(isInRegion(g, ['US', 'CA', 'MX']), true)
  assert.strictEqual(isInRegion(g, ['us', 'ca']), true) // case-insensitive
  assert.strictEqual(isInRegion(g, ['GB', 'DE']), false)
  assert.strictEqual(isInRegion({}, ['US']), false) // missing countryCode
  console.log('✓ isInRegion() with matching/non-matching regions')
}

// Test geoDistance() - New York to London ~5570 km (allow 50 km tolerance)
{
  // New York:  40.7128° N, 74.0060° W
  // London:   51.5074° N,  0.1278° W
  const distance = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
  assert.ok(
    Math.abs(distance - 5570) < 50,
    `Expected ~5570 km, got ${distance.toFixed(1)} km`
  )
  console.log(`✓ geoDistance() New York to London: ${distance.toFixed(1)} km`)
}

// Test that missing headers return undefined fields
{
  const headers = new Headers({})
  const result = geo({ headers })
  assert.strictEqual(result.city, undefined)
  assert.strictEqual(result.country, undefined)
  assert.strictEqual(result.countryCode, undefined)
  assert.strictEqual(result.region, undefined)
  assert.strictEqual(result.latitude, undefined)
  assert.strictEqual(result.longitude, undefined)
  assert.strictEqual(result.timezone, undefined)
  console.log('✓ Missing headers return undefined fields')
}

// Test country name lookup for all 10 supported country codes
{
  const expected: Record<string, string> = {
    US: 'United States',
    GB: 'United Kingdom',
    DE: 'Germany',
    FR: 'France',
    JP: 'Japan',
    CN: 'China',
    IN: 'India',
    BR: 'Brazil',
    AU: 'Australia',
    CA: 'Canada',
  }
  for (const [code, name] of Object.entries(expected)) {
    const headers = new Headers({ 'x-vercel-ip-country': code })
    const result = geoFromHeaders(headers)
    assert.strictEqual(
      result.country,
      name,
      `Expected country "${name}" for code "${code}"`
    )
  }
  console.log('✓ Country name lookup from countryCode')
}

console.log('\nAll tests passed!')

